SELECT COUNT(*) AS total_active_addresses
FROM addresses
WHERE borough = 'Manhattan' AND is_active = 1;

SELECT AVG(latitude) AS average_latitude
FROM addresses
WHERE is_active = 1 AND borough = 'Manhattan';

SELECT change_date, change_type, user_id
FROM address_history
ORDER BY change_date DESC;

SELECT latitude, longitude 
FROM addresses
WHERE longitude = (SELECT MAX(longitude) FROM addresses);
